mapper.update:
UPDATE withdrawal_requests
SET status = 'COMPLETED',
    processed_at = #{processedAt}
WHERE id = #{id}

UPDATE withdrawal_requests
SET status = 'REJECTED',
    reject_reason = #{rejectReason},
    processed_at = #{processedAt}
WHERE id = #{id}

mapper.select:
SELECT id, source_type, amount, fee_amount, net_transfer_amount,
bank_name, account_number, account_holder_name,
status, reject_reason, requested_at, processed_at
FROM withdrawal_requests
WHERE wallet_id = #{walletId}

    AND status = #{status}

ORDER BY requested_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM withdrawal_requests
WHERE wallet_id = #{walletId}

    AND status = #{status}

SELECT wr.id, w.user_id AS userId, wr.source_type, wr.amount, wr.fee_amount, wr.net_transfer_amount, wr.bank_name, wr.account_number, wr.account_holder_name, wr.status, wr.reject_reason, wr.requested_at, wr.processed_at FROM withdrawal_requests wr JOIN wallets w ON w.id = wr.wallet_id
WHERE wr.status = #{status}
ORDER BY wr.requested_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM withdrawal_requests

    WHERE status = #{status}
